using System.Collections;
using System.Collections.Generic;
using UnityEngine;

public class PlayerStats : MonoBehaviour
{
    public int health = 100;
    public int currency = 0;

    private const string SECRET_KEY = "your_secret_key_here";

    public void TakeDamage(int damage)
    {
        if (damage > 0)
        {
            health -= damage;
            Debug.Log("Player took " + damage + " damage. Current health: " + health);
        }
    }

    public void AddCurrency(int amount)
    {
        if (amount > 0)
        {
            currency += amount;
            Debug.Log("Added " + amount + " currency to player's balance.");
        }
    }

    public int CalculatePrice(int itemCost, int discount = 0)
    {
        if (itemCost >= 0 && discount >= 0)
        {
            return itemCost - (discount * itemCost / 100);
        }
        else
        {
            Debug.LogError("Invalid price or discount value.");
            return 0;
        }
    }

    public int CalculateDamage(int damage, float multiplier = 1f)
    {
        if (damage >= 0 && multiplier > 0)
        {
            return Mathf.RoundToInt(damage * multiplier);
        }
        else
        {
            Debug.LogError("Invalid damage or multiplier value.");
            return 0;
        }
    }

    public void PurchaseItem(int itemCost, int discount = 0)
    {
        if (itemCost >= 0 && currency >= CalculatePrice(itemCost, discount))
        {
            AddCurrency(-CalculatePrice(itemCost, discount));
            Debug.Log("Player purchased item for " + CalculatePrice(itemCost, discount) + " currency.");
        }
        else
        {
            Debug.LogError("Insufficient funds or invalid price/discount value.");
        }
    }

    private void OnApplicationPause(bool pause)
    {
        if (pause)
        {
            PlayerPrefs.SetInt("health", health);
            PlayerPrefs.SetInt("currency", currency);
        }
        else
        {
            health = PlayerPrefs.GetInt("health");
            currency = PlayerPrefs.GetInt("currency");
        }
    }
}

public class Shop : MonoBehaviour
{
    public PlayerStats player;
    public int[] itemPrices;

    private void Start()
    {
        foreach (int price in itemPrices)
        {
            Debug.Log("Item price: " + price);
        }
    }

    public void BuyItem(int index)
    {
        if (index >= 0 && index < itemPrices.Length)
        {
            player.PurchaseItem(itemPrices[index]);
        }
        else
        {
            Debug.LogError("Invalid item index.");
        }
    }
}